def calculer_montant_total(self):
    delta = self.dateFin - self.dateDebut
    nb_jours = max(delta.days, 1)

    total = 0
    if self.element and self.element.tarifs:
        total += self.element.tarifs[0].prixParJour * nb_jours

    for m in self.materiels:
        total += 50

    self.montantTotal = total
    return total

